// // This module decrements the count value on every positive clock edge and sets the count to 0 when the reset signal is low.
module sync_counter_4bit(
    input clk, 
    input reset, 
    output reg [3:0] count);

    always @(posedge clk) begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end
endmodule
